"use strict";

var runtimeFetch = globalThis.fetch.bind(globalThis);
var observedRedirectModes = [];
var blockedTargetHits = 0;

module.exports.fetch = function(input, init) {
    if (String(input) === "https://fetch.example.test/redirect-guard-test") {
        observedRedirectModes.push(init && init.redirect);
        return Promise.resolve({ redirected: init && init.redirect !== "error" });
    }
    if (String(input) === "http://downgrade.example.test/resource") {
        blockedTargetHits++;
        return Promise.resolve({ status: 200 });
    }
    if (/^http:\/\/127\.0\.0\.1:45678\/wait-for-auth(?:\?poll=false)?$/.test(
            String(input)))
        return Promise.resolve({ status: 202 });
    return runtimeFetch(input, init);
};
module.exports.testRawFetch = module.exports.fetch;
module.exports.testRedirectModes = observedRedirectModes;
module.exports.testBlockedTargetHits = function() { return blockedTargetHits; };

module.exports.install = function() {
    globalThis.fetch = module.exports.fetch;
};
